build.VisitAllChildren<Target>(t => {
    if (t.Name == "CoreCompile" || t.Name == "Build") {
        if (!t.Succeeded)
            Console.WriteLine($"  FAILED target '{t.Name}' in {t.Project?.Name}");
    }
});
