using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;

var build = BinaryLog.ReadBuild("/tmp/sv-7e0921a7a3cb46e3b6482535e81994d1/build.binlog");

// Check why Core failed
Console.WriteLine("=== Core.csproj failed targets details ===");
build.VisitAllChildren<Target>(t => {
    if (!t.Succeeded && t.Project?.Name == "Core.csproj") {
        Console.WriteLine($"  Target: {t.Name}, Project: {t.Project?.ProjectFile}");
        t.VisitAllChildren<Message>(m => {
            if (m.Text != null && m.Text.Length < 300)
                Console.WriteLine($"    MSG: {m.Text}");
        });
        t.VisitAllChildren<Error>(e => {
            Console.WriteLine($"    ERR: {e.Code}: {e.Text}");
        });
    }
});

// Check for dependency-related messages
Console.WriteLine("\n=== Messages about project dependencies failing ===");
build.VisitAllChildren<Message>(m => {
    if (m.Text != null && (m.Text.Contains("GetTargetPath") || m.Text.Contains("ResolveProjectReferences")))
        if (m.Text.Length < 300)
            Console.WriteLine($"  {m.Text}");
});
EOF
dotnet run 2>&1

